export declare const demoThemeTemplate = "\"use client\";\nimport React from \"react\";\nimport { Button } from \"@/components/layout/Button\";\nimport { useThemeOverride } from \"@/components/layout/ClientThemeProvider\";\nimport { Theme, theme, themeDark } from \"@/app/theme\";\nimport { Columns } from \"@/components/layout/Columns\";\n\ninterface DemoThemeProps {\n  variant: \"purple\" | \"green\" | \"yellow\";\n}\n\nfunction DemoTheme({ variant }: DemoThemeProps) {\n  const { setTheme } = useThemeOverride();\n\n  const purpleLight: Theme = {\n    ...theme,\n    colors: {\n      primaryLight: \"#c4b5fd\",\n      primary: \"#8b5cf6\",\n      primaryDark: \"#5b21b6\",\n      secondaryLight: \"#86efac\",\n      secondary: \"#22c55e\",\n      secondaryDark: \"#15803d\",\n      tertiaryLight: \"#fbbf24\",\n      tertiary: \"#f59e0b\",\n      tertiaryDark: \"#d97706\",\n      grayLight: \"#f3f4f6\",\n      gray: \"#9ca3af\",\n      grayDark: \"#374151\",\n      success: \"#10b981\",\n      error: \"#f43f5e\",\n      warning: \"#f59e0b\",\n      info: \"#3b82f6\",\n      dark: \"#000000\",\n      light: \"#ffffff\",\n    },\n  };\n\n  const purpleDark: Theme = {\n    ...themeDark,\n    colors: {\n      primaryLight: \"#ddd6fe\",\n      primary: \"#a78bfa\",\n      primaryDark: \"#7c3aed\",\n      secondaryLight: \"#6ee7b7\",\n      secondary: \"#10b981\",\n      secondaryDark: \"#065f46\",\n      tertiaryLight: \"#fed7aa\",\n      tertiary: \"#fb923c\",\n      tertiaryDark: \"#ea580c\",\n      grayLight: \"#1f2937\",\n      gray: \"#6b7280\",\n      grayDark: \"#9ca3af\",\n      success: \"#10b981\",\n      error: \"#f43f5e\",\n      warning: \"#f59e0b\",\n      info: \"#3b82f6\",\n      dark: \"#ffffff\",\n      light: \"#000000\",\n    },\n  };\n\n  const greenLight: Theme = {\n    ...theme,\n    colors: {\n      primaryLight: \"#86efac\",\n      primary: \"#22c55e\",\n      primaryDark: \"#15803d\",\n      secondaryLight: \"#c4b5fd\",\n      secondary: \"#8b5cf6\",\n      secondaryDark: \"#5b21b6\",\n      tertiaryLight: \"#fbbf24\",\n      tertiary: \"#f59e0b\",\n      tertiaryDark: \"#d97706\",\n      grayLight: \"#f3f4f6\",\n      gray: \"#9ca3af\",\n      grayDark: \"#374151\",\n      success: \"#10b981\",\n      error: \"#f43f5e\",\n      warning: \"#f59e0b\",\n      info: \"#3b82f6\",\n      dark: \"#000000\",\n      light: \"#ffffff\",\n    },\n  };\n\n  const greenDark: Theme = {\n    ...themeDark,\n    colors: {\n      primaryLight: \"#6ee7b7\",\n      primary: \"#10b981\",\n      primaryDark: \"#065f46\",\n      secondaryLight: \"#ddd6fe\",\n      secondary: \"#a78bfa\",\n      secondaryDark: \"#7c3aed\",\n      tertiaryLight: \"#fed7aa\",\n      tertiary: \"#fb923c\",\n      tertiaryDark: \"#ea580c\",\n      grayLight: \"#1f2937\",\n      gray: \"#6b7280\",\n      grayDark: \"#9ca3af\",\n      success: \"#10b981\",\n      error: \"#f43f5e\",\n      warning: \"#f59e0b\",\n      info: \"#3b82f6\",\n      dark: \"#ffffff\",\n      light: \"#000000\",\n    },\n  };\n\n  const yellowLight: Theme = {\n    ...theme,\n    colors: {\n      primaryLight: \"#fbbf24\",\n      primary: \"#f59e0b\",\n      primaryDark: \"#d97706\",\n      secondaryLight: \"#c4b5fd\",\n      secondary: \"#8b5cf6\",\n      secondaryDark: \"#5b21b6\",\n      tertiaryLight: \"#86efac\",\n      tertiary: \"#22c55e\",\n      tertiaryDark: \"#15803d\",\n      grayLight: \"#f3f4f6\",\n      gray: \"#9ca3af\",\n      grayDark: \"#374151\",\n      success: \"#10b981\",\n      error: \"#f43f5e\",\n      warning: \"#f59e0b\",\n      info: \"#3b82f6\",\n      dark: \"#000000\",\n      light: \"#ffffff\",\n    },\n  };\n\n  const yellowDark: Theme = {\n    ...themeDark,\n    colors: {\n      primaryLight: \"#fed7aa\",\n      primary: \"#fb923c\",\n      primaryDark: \"#ea580c\",\n      secondaryLight: \"#ddd6fe\",\n      secondary: \"#a78bfa\",\n      secondaryDark: \"#7c3aed\",\n      tertiaryLight: \"#6ee7b7\",\n      tertiary: \"#10b981\",\n      tertiaryDark: \"#065f46\",\n      grayLight: \"#1f2937\",\n      gray: \"#6b7280\",\n      grayDark: \"#9ca3af\",\n      success: \"#10b981\",\n      error: \"#f43f5e\",\n      warning: \"#f59e0b\",\n      info: \"#3b82f6\",\n      dark: \"#ffffff\",\n      light: \"#000000\",\n    },\n  };\n\n  if (variant === \"purple\") {\n    return (\n      <Columns cols={2}>\n        <Button onClick={() => setTheme(purpleLight)} icon=\"sun\" fullWidth>\n          Demo Purple Light\n        </Button>\n        <Button\n          outline\n          onClick={() => setTheme(purpleDark)}\n          icon=\"moon-star\"\n          fullWidth\n        >\n          Demo Purple Dark\n        </Button>\n      </Columns>\n    );\n  }\n\n  if (variant === \"green\") {\n    return (\n      <Columns cols={2}>\n        <Button onClick={() => setTheme(greenLight)} icon=\"sun\" fullWidth>\n          Demo Green Light\n        </Button>\n        <Button\n          outline\n          onClick={() => setTheme(greenDark)}\n          icon=\"moon-star\"\n          fullWidth\n        >\n          Demo Green Dark\n        </Button>\n      </Columns>\n    );\n  }\n\n  if (variant === \"yellow\") {\n    return (\n      <Columns cols={2}>\n        <Button onClick={() => setTheme(yellowLight)} icon=\"sun\" fullWidth>\n          Demo Yellow Light\n        </Button>\n        <Button\n          outline\n          onClick={() => setTheme(yellowDark)}\n          icon=\"moon-star\"\n          fullWidth\n        >\n          Demo Yellow Dark\n        </Button>\n      </Columns>\n    );\n  }\n\n  return (\n    <Columns cols={2}>\n      <Button onClick={() => setTheme(null)} fullWidth>\n        Reset to Default\n      </Button>\n    </Columns>\n  );\n}\n\nexport { DemoTheme };\n";
